SELECT DISTINCT ?club ?kitColor 
WHERE {
  ?league rdfs:label "Isle of Man Football League"@en ;
            wdt:P31 wd:Q24052951 .
  ?club wdt:P31 wd:Q353734 ;
        wdt:P304 ?league ;
        wdt:P991 ?kitColor .
}

SELECT ?club ?kitColor WHERE {
  wd:Q30640603 wdt:P31 wd:Q24052951 ;
                rdfs:label "Isle of Man Premier League"@en .
